+function replaceEarlierValues(world: World, entity: Entity, traits: ConfigurableTrait[]) {
+    const list = commands(world);
+    for (const config of traits) {
+        const key = traitKey(config);
+        for (let i = list.length - 1; i >= 0; i--) {
+            const command = list[i];
+            if (command.entity !== entity || command.type !== 'add') continue;
+            const index = command.traits.findIndex((item) => traitKey(item) === key);
+            if (index !== -1) command.traits.splice(index, 1);
+            if (command.traits.length === 0) list.splice(i, 1);
+        }
+    }
+}
+
+export function createDeferredWorld(world: World): DeferredWorld {
+    return {
+        spawn(...traits) {
+            const entity = allocateEntity(world[$internal].entityIndex);
+            commands(world).push({ type: 'spawn', entity, traits });
+            world[$internal].deferredSpawns.add(entity);
+            return entity;
+        },
+        destroy(entity) {
+            commands(world).push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            replaceEarlierValues(world, entity, traits);
+            commands(world).push({ type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            commands(world).push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, ...traits) {
+            replaceEarlierValues(world, entity, traits);
+            commands(world).push({ type: 'exclusive', entity, traits });
+        },
+        flush() {
+            flushDeferred(world);
