+// A small overlay is enough for reads: commands are applied in order and only
+// the requested trait/pair is considered. This keeps reads non-mutating while
+// a query is being iterated.
+export function deferredHas(world: World, entity: Entity, target: Trait | RelationPair): boolean {
+    let value = isRelationPair(target)
+        ? entity.has(target)
+        : hasTrait(world, entity, target as Trait);
+    for (const command of commands(world)) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'destroy') return false;
+        if (command.type === 'spawn') value = false;
+        const traits = command.type === 'spawn' ? command.traits : command.type === 'add' || command.type === 'exclusive' ? command.traits : command.type === 'remove' ? command.traits : [];
