+            const targetKey = traitKey(target as ConfigurableTrait);
+            if (itemKey !== targetKey) continue;
+            if (command.type === 'remove') value = false;
+            else if (command.type === 'exclusive' && isRelationPair(item) && item[$internal].target === '*') value = false;
+            else value = true;
+        }
+    }
