+export function deferredGet(world: World, entity: Entity, target: Trait | RelationPair) {
+    let value = getTrait(world, entity, target);
+    for (const command of commands(world)) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'destroy' || command.type === 'spawn') value = undefined;
+        const traits = command.type === 'add' || command.type === 'exclusive' || command.type === 'spawn' ? command.traits : [];
+        if (command.type === 'remove' && command.traits.some((item) => traitKey(item as ConfigurableTrait) === traitKey(target as ConfigurableTrait))) value = undefined;
+        for (const item of traits) {
+            if (traitKey(item) !== traitKey(target as ConfigurableTrait)) continue;
+            if (isRelationPair(item) && item[$internal].target === '*') value = undefined;
+            else if (Array.isArray(item)) value = item[1] as any;
+            else if (isRelationPair(item)) value = item[$internal].params as any;
+        }
+    }
+    return value;
+}
