+export function flushDeferred(world: World) {
+    const ctx = world[$internal];
+    if (ctx.flushingDeferred || ctx.deferredCommands.length === 0) return;
+    const pending = ctx.deferredCommands;
+    ctx.deferredCommands = [];
+    ctx.flushingDeferred = true;
+    try {
+        for (const command of pending) {
+            if (command.type === 'spawn') {
+                // Spawn + destroy is deliberately a no-op, including subscriptions.
+                if (pending.some((item) => item.type === 'destroy' && item.entity === command.entity)) {
