+type SubscriptionSnapshot = {
+    traits: Map<Trait, Map<Entity, Entity[] | true>>;
+    queries: Map<any, Set<Entity>>;
+};
+
+function captureSubscriptions(world: World): SubscriptionSnapshot {
+    const ctx = world[$internal];
+    const entities = ctx.entityIndex.dense.slice(0, ctx.entityIndex.aliveCount);
+    const traits = new Map<Trait, Map<Entity, Entity[] | true>>();
+    for (const instance of ctx.traitInstances) {
+        if (!instance) continue;
+        const states = new Map<Entity, Entity[] | true>();
+        const relation = instance.trait[$internal].relation;
+        for (const entity of entities) {
+            if (!hasTrait(world, entity, instance.trait)) continue;
+            states.set(entity, relation ? [...getRelationTargets(world, relation, entity)] : true);
+        }
+        traits.set(instance.trait, states);
+    }
+    const queries = new Map<any, Set<Entity>>();
+    for (const query of ctx.queriesHashMap.values()) queries.set(query, new Set(query.entities.dense));
+    return { traits, queries };
+}
+
+type MutedSubscriptions = [Set<any>, any[]][];
+function muteSubscriptions(world: World): MutedSubscriptions {
+    const muted: MutedSubscriptions = [];
+    const clear = (set: Set<any>) => {
+        if (!set.size) return;
+        const values = [...set];
+        muted.push([set, values]);
+        set.clear();
+    };
+    const ctx = world[$internal];
+    for (const instance of ctx.traitInstances) {
+        if (!instance) continue;
+        clear(instance.addSubscriptions);
+        clear(instance.removeSubscriptions);
+        clear(instance.changeSubscriptions);
+    }
+    for (const query of ctx.queriesHashMap.values()) {
+        clear(query.addSubscriptions);
+        clear(query.removeSubscriptions);
+    }
+    return muted;
+}
+
+function restoreSubscriptions(muted: MutedSubscriptions) {
+    for (const [set, values] of muted) for (const value of values) set.add(value);
+}
